export function useOrdersApi() {
    const { $api } = useNuxtApp()
    return {
        create(data: any) { return $api<any>('/orders', { method: 'POST', body: data }) },
        getMyOrders(params?: { page?: number; limit?: number }) { return $api<any>('/orders/me', { params }) },
        findById(id: string) { return $api<any>(`/orders/${id}`) },
    }
}
